import React from 'react';
import { Card, Stack, Divider, Text, Heading, Box } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent(props: Props) {
  const {
    city,
    temperature,
    condition,
    humidity,
    windSpeed,
    unit = 'C',
    forecast,
  } = props;

  return (
    <Card 
      shadow="md" 
      padding="var(--ggui-spacing-6, 24px)" 
      radius="lg" 
      border={true}
      aria-label={`Weather in ${city}: ${condition}, ${temperature}°${unit}`}
    >
      <Stack gap="var(--ggui-spacing-4, 16px)">
        {/* Header: City & Condition */}
        <Stack direction="vertical" gap="var(--ggui-spacing-1, 4px)">
          <Heading level={2}>{city}</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-neutral-500, #6b7280)">
            {condition}
          </Text>
        </Stack>

        {/* Current Temp */}
        <Stack direction="horizontal" align="center" justify="between">
          <Heading level={1} color="var(--ggui-color-primary-600, #0284c7)">
            {temperature}°{unit}
          </Heading>
          <Box borderRadius="var(--ggui-shape-radius-md, 8px)" padding="var(--ggui-spacing-2, 8px)" background="var(--ggui-color-neutral-100, #f3f4f6)">
            <Text size="3xl">
              {condition === 'Sunny' ? '☀️' : condition === 'Cloudy' ? '⛅' : condition === 'Rainy' ? '🌧️' : '🌡️'}
            </Text>
          </Box>
        </Stack>

        {/* Details Strip */}
        <Stack direction="horizontal" gap="var(--ggui-spacing-6, 24px)">
          <Stack direction="vertical" gap="var(--ggui-spacing-1, 4px)">
            <Text variant="overline" color="var(--ggui-color-neutral-500, #6b7280)">HUMIDITY</Text>
            <Text variant="label">{humidity}%</Text>
          </Stack>
          <Stack direction="vertical" gap="var(--ggui-spacing-1, 4px)">
            <Text variant="overline" color="var(--ggui-color-neutral-500, #6b7280)">WIND</Text>
            <Text variant="label">{windSpeed} km/h</Text>
          </Stack>
        </Stack>

        <Divider margin="var(--ggui-spacing-4, 16px)" />

        {/* Forecast Strip */}
        <Stack direction="horizontal" justify="between" align="start">
          {forecast.map((item, index) => (
            <Stack key={index} direction="vertical" align="center" gap="var(--ggui-spacing-2, 8px)">
              <Text variant="label">{item.day ?? 'Day'}</Text>
              <Text size="xl">{item.icon ?? '❓'}</Text>
              <Stack direction="horizontal" gap="var(--ggui-spacing-1, 4px)">
                <Text variant="bodySmall" weight="bold">{item.high ?? '--'}°</Text>
                <Text variant="bodySmall" color="var(--ggui-color-neutral-500, #6b7280)">{item.low ?? '--'}°</Text>
              </Stack>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState } from 'react';
import { Container, Card, Stack, Box, Text, Heading, Input } from '@ggui-ai/design/primitives';

interface Props {
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

const CATEGORY_COLORS: Record<string, string> = {
  'alkali-metal': 'var(--ggui-color-primary-300)',
  'alkaline-earth-metal': 'var(--ggui-color-primary-400)',
  'transition-metal': 'var(--ggui-color-primary-500)',
  'post-transition-metal': 'var(--ggui-color-primary-600)',
  'metalloid': 'var(--ggui-color-warning-500)',
  'nonmetal': 'var(--ggui-color-success-500)',
  'halogen': 'var(--ggui-color-info-500)',
  'noble-gas': 'var(--ggui-color-error-500)',
  'lanthanide': 'var(--ggui-color-neutral-500)',
  'actinide': 'var(--ggui-color-neutral-500)',
};

export default function GeneratedComponent(props: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<Props['elements'][0] | null>(null);

  const filteredElements = props.elements.filter((e) =>
    (e.name?.toLowerCase() ?? '').includes(searchQuery.toLowerCase()) ||
    (e.symbol?.toLowerCase() ?? '').includes(searchQuery.toLowerCase())
  );

  const isMatch = (e: Props['elements'][0]) =>
    searchQuery === '' || 
    (e.name?.toLowerCase() ?? '').includes(searchQuery.toLowerCase()) ||
    (e.symbol?.toLowerCase() ?? '').includes(searchQuery.toLowerCase());

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-4, 16px)">
        <Heading level={2}>Periodic Table</Heading>

        <Input 
          label="Search elements"
          placeholder="Search by name or symbol..." 
          value={searchQuery} 
          onChange={setSearchQuery} 
          type="search"
        />

        <Box 
          style={{ 
            display: 'grid', 
            gridTemplateColumns: 'repeat(18, 1fr)', 
            gap: 'var(--ggui-spacing-1, 4px)' 
          }}
        >
          {props.elements.map((el, i) => (
            <div 
              key={i}
              style={{
                gridRow: el.row,
                gridColumn: el.col,
                opacity: isMatch(el) ? 1 : 0.2,
                cursor: isMatch(el) ? 'pointer' : 'default',
              }}
              onClick={() => isMatch(el) && setSelectedElement(el)}
            >
              <Card 
                padding="var(--ggui-spacing-2, 8px)" 
                style={{
                  aspectRatio: '1/1',
                  display: 'flex',
                  flexDirection: 'column',
                  justifyContent: 'center',
                  alignItems: 'center',
                  backgroundColor: CATEGORY_COLORS[el.category ?? ''] ?? 'var(--ggui-color-neutral-200)',
                }}
              >
                <Text variant="caption" style={{ alignSelf: 'flex-start' }}>{el.atomicNumber}</Text>
                <Heading level={5}>{el.symbol}</Heading>
              </Card>
            </div>
          ))}
        </Box>

        {selectedElement && (
          <Card padding="var(--ggui-spacing-4, 16px)">
            <Stack gap="var(--ggui-spacing-2, 8px)">
              <Heading level={3}>{selectedElement.name}</Heading>
              <Text>Symbol: {selectedElement.symbol}</Text>
              <Text>Atomic Number: {selectedElement.atomicNumber}</Text>
              <Text>Atomic Weight: {selectedElement.atomicWeight}</Text>
              <Text>Category: {selectedElement.category}</Text>
            </Stack>
          </Card>
        )}

        <Stack direction="horizontal" gap="var(--ggui-spacing-4, 16px)" wrap>
          {Object.entries(CATEGORY_COLORS).map(([cat, color]) => (
            <Stack key={cat} direction="horizontal" gap="var(--ggui-spacing-1, 4px)" align="center">
              <Box style={{ width: '12px', height: '12px', backgroundColor: color, borderRadius: '2px' }} />
              <Text variant="caption">{cat.replace('-', ' ')}</Text>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Container>
  );
}

import React from 'react';
import { 
  Card, 
  Stack, 
  Heading, 
  Text, 
  Divider, 
  Box, 
  Spacer 
} from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ 
    day?: string; 
    icon?: string; 
    high?: number; 
    low?: number 
  }>;
}

/**
 * WeatherCard Component
 * Displays a comprehensive weather overview including current conditions and a 5-day forecast.
 */
export default function GeneratedComponent(props: Props) {
  const {
    city,
    temperature,
    condition,
    humidity,
    windSpeed,
    unit = 'C',
    forecast = []
  } = props;

  const tempUnit = `°${unit}`;
  const roundedTemp = Math.round(temperature);

  return (
    <Card 
      shadow="md" 
      radius="xl" 
      padding={24} 
      border={true}
    >
      <Stack gap={24} align="stretch">
        {/* Header: City and Condition */}
        <Stack gap={4} align="center">
          <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
            {city}
          </Heading>
          <Text 
            variant="label" 
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
          >
            {condition}
          </Text>
        </Stack>

        {/* Main Temperature Display */}
        <Stack align="center" gap={0}>
          <Stack direction="horizontal" align="start" gap={2}>
            <Text 
              size="4xl" 
              weight="bold" 
              color="var(--ggui-color-onSurface, #18181b)"
            >
              {roundedTemp}
            </Text>
            <Box margin="var(--ggui-spacing-2, 8px) 0 0 0">
              <Text 
                variant="bodyLarge" 
                weight="semibold" 
                color="var(--ggui-color-primary-600, #0284c7)"
              >
                {tempUnit}
              </Text>
            </Box>
          </Stack>
        </Stack>

        {/* Details Row: Humidity and Wind */}
        <Stack direction="horizontal" justify="between" gap={12}>
          <Box 
            padding={12} 
            borderRadius="var(--ggui-shape-radius-lg, 12px)" 
            background="var(--ggui-color-surfaceVariant, #f4f4f5)"
            style={{ flex: 1 }}
          >
            <Stack align="center" gap={4}>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                HUMIDITY
              </Text>
              <Text weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                {humidity}%
              </Text>
            </Stack>
          </Box>
          <Box 
            padding={12} 
            borderRadius="var(--ggui-shape-radius-lg, 12px)" 
            background="var(--ggui-color-surfaceVariant, #f4f4f5)"
            style={{ flex: 1 }}
          >
            <Stack align="center" gap={4}>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                WIND
              </Text>
              <Text weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                {windSpeed} km/h
              </Text>
            </Stack>
          </Box>
        </Stack>

        <Divider margin={0} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

        {/* 5-Day Forecast Strip */}
        <Stack direction="horizontal" justify="between" gap={8} align="center">
          {forecast.map((item, index) => (
            <Stack 
              key={`${item.day}-${index}`} 
              align="center" 
              gap={8}
              style={{ flex: 1 }}
            >
              <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {item.day ?? '---'}
              </Text>

              <Box paddingY={4}>
                <Text size="lg">
                  {item.icon ?? '☁️'}
                </Text>
              </Box>

              <Stack gap={2} align="center">
                <Text 
                  variant="bodySmall" 
                  weight="semibold" 
                  color="var(--ggui-color-onSurface, #18181b)"
                >
                  {Math.round(item.high ?? 0)}°
                </Text>
                <Text 
                  variant="caption" 
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                >
                  {Math.round(item.low ?? 0)}°
                </Text>
              </Stack>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Container,
  Stack,
  Card,
  Box,
  Text,
  Heading,
  Badge,
  Divider,
  Spacer,
} from '@ggui-ai/design/primitives';
import { SearchField, FormField } from '@ggui-ai/design/components';

interface Props {
  /** Full periodic table element data */
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

export default function GeneratedComponent({ elements = [] }: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | null>(null);

  const filteredElements = useMemo(() => {
    return elements.map((el) => {
      const matches =
        el.name?.toLowerCase().includes(searchQuery.toLowerCase()) ||
        el.symbol?.toLowerCase().includes(searchQuery.toLowerCase());
      return { ...el, matches };
    });
  }, [elements, searchQuery]);

  const selectedElement = useMemo(
    () => elements.find((el) => el.atomicNumber === selectedAtomicNumber),
    [elements, selectedAtomicNumber]
  );

  const getCategoryColor = (category?: string) => {
    const cat = category?.toLowerCase() || '';
    if (cat.includes('alkali metal')) return 'var(--ggui-color-primary-100, #e0f2fe)';
    if (cat.includes('noble gas')) return 'var(--ggui-color-info-100, #cffafe)';
    if (cat.includes('alkaline earth')) return 'var(--ggui-color-warning-100, #fef3c7)';
    if (cat.includes('halogen')) return 'var(--ggui-color-warning-50, #fffbeb)';
    if (cat.includes('metalloid')) return 'var(--ggui-color-success-100, #dcfce7)';
    if (cat.includes('nonmetal')) return 'var(--ggui-color-info-50, #ecfeff)';
    if (cat.includes('transition metal')) return 'var(--ggui-color-neutral-100, #f3f4f6)';
    if (cat.includes('post-transition')) return 'var(--ggui-color-neutral-200, #e5e7eb)';
    if (cat.includes('lanthanide')) return 'var(--ggui-color-primary-50, #f0f9ff)';
    if (cat.includes('actinide')) return 'var(--ggui-color-primary-200, #bae6fd)';
    return 'var(--ggui-color-neutral-50, #f9fafb)';
  };

  const categories = [
    { label: 'Alkali Metal', color: 'var(--ggui-color-primary-100, #e0f2fe)' },
    { label: 'Alkaline Earth', color: 'var(--ggui-color-warning-100, #fef3c7)' },
    { label: 'Transition Metal', color: 'var(--ggui-color-neutral-100, #f3f4f6)' },
    { label: 'Post-transition', color: 'var(--ggui-color-neutral-200, #e5e7eb)' },
    { label: 'Metalloid', color: 'var(--ggui-color-success-100, #dcfce7)' },
    { label: 'Nonmetal', color: 'var(--ggui-color-info-50, #ecfeff)' },
    { label: 'Halogen', color: 'var(--ggui-color-warning-50, #fffbeb)' },
    { label: 'Noble Gas', color: 'var(--ggui-color-info-100, #cffafe)' },
    { label: 'Lanthanide', color: 'var(--ggui-color-primary-50, #f0f9ff)' },
    { label: 'Actinide', color: 'var(--ggui-color-primary-200, #bae6fd)' },
  ];

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-8, 32px)">
        {/* Header Section */}
        <Stack direction="horizontal" justify="between" align="end" wrap>
          <Stack gap="var(--ggui-spacing-1, 4px)">
            <Heading level={1} color="var(--ggui-color-onSurface, #18181b)">
              Periodic Table
            </Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Explore the chemical elements by name, symbol, or properties.
            </Text>
          </Stack>
          <Box style={{ width: '100%', maxWidth: '400px' }}>
            <FormField label="Search elements" description="Filter by element name or symbol">
              <SearchField
                placeholder="Search (e.g. Gold, Au)..."
                value={searchQuery}
                onChange={setSearchQuery}
              />
            </FormField>
          </Box>
        </Stack>

        {/* Legend */}
        <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" wrap>
          {categories.map((cat) => (
            <Box
              key={cat.label}
              paddingX="var(--ggui-spacing-2, 8px)"
              paddingY="var(--ggui-spacing-1, 4px)"
              borderRadius="var(--ggui-shape-radius-sm, 4px)"
              background={cat.color}
              style={{ border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)' }}
            >
              <Text variant="caption" weight="medium" color="var(--ggui-color-onSurface, #18181b)">
                {cat.label}
              </Text>
            </Box>
          ))}
        </Stack>

        {/* Grid Container */}
        <Box
          style={{
            overflowX: 'auto',
            paddingBottom: 'var(--ggui-spacing-4, 16px)',
          }}
        >
          <div
            role="grid"
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(18, minmax(60px, 1fr))',
              gap: 'var(--ggui-spacing-1, 4px)',
              minWidth: '1000px',
            }}
          >
            {filteredElements.map((el) => {
              const isSelected = selectedAtomicNumber === el.atomicNumber;
              const bgColor = getCategoryColor(el.category);

              return (
                <div
                  key={el.atomicNumber}
                  role="gridcell"
                  tabIndex={0}
                  aria-label={el.name ?? 'Element'}
                  onClick={() => setSelectedAtomicNumber(el.atomicNumber ?? null)}
                  onKeyDown={(e) => {
                    if (e.key === 'Enter' || e.key === ' ') {
                      setSelectedAtomicNumber(el.atomicNumber ?? null);
                    }
                  }}
                  style={{
                    gridRow: el.row,
                    gridColumn: el.col,
                    cursor: 'pointer',
                    transition: 'all 200ms cubic-bezier(0.4, 0, 0.2, 1)',
                    opacity: el.matches ? 1 : 0.2,
                    filter: el.matches ? 'none' : 'grayscale(0.8)',
                    transform: isSelected ? 'scale(1.05)' : 'none',
                    zIndex: isSelected ? 10 : 1,
                  }}
                >
                  <Box
                    padding="var(--ggui-spacing-1, 4px)"
                    borderRadius="var(--ggui-shape-radius-sm, 4px)"
                    background={bgColor}
                    style={{
                      height: '72px',
                      display: 'flex',
                      flexDirection: 'column',
                      justifyContent: 'space-between',
                      border: isSelected
                        ? '2px solid var(--ggui-color-primary-600, #0284c7)'
                        : '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                      boxShadow: isSelected ? 'var(--ggui-shape-shadow-md)' : 'none',
                    }}
                  >
                    <Text size="xs" variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      {el.atomicNumber}
                    </Text>
                    <Text weight="bold" size="lg" align="center" color="var(--ggui-color-onSurface, #18181b)">
                      {el.symbol}
                    </Text>
                    <Text
                      variant="caption"
                      size="xs"
                      align="center"
                      truncate
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    >
                      {el.name}
                    </Text>
                  </Box>
                </div>
              );
            })}
          </div>
        </Box>

        {/* Detail Panel */}
        {selectedElement && (
          <Box style={{ animation: 'ggui-slideInUp 300ms ease-out' }} aria-live="polite">
            <Card shadow="md" padding="var(--ggui-spacing-6, 24px)" radius="lg">
              <Stack gap="var(--ggui-spacing-4, 16px)">
                <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-4, 16px)">
                  <Box
                    padding="var(--ggui-spacing-4, 16px)"
                    borderRadius="var(--ggui-shape-radius-md, 8px)"
                    background={getCategoryColor(selectedElement.category)}
                    style={{
                      minWidth: '80px',
                      border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                    }}
                  >
                    <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
                      {selectedElement.symbol}
                    </Heading>
                  </Box>
                  <Stack gap="var(--ggui-spacing-1, 4px)">
                    <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
                      {selectedElement.name}
                    </Heading>
                    <Badge variant="primary" size="md">
                      {selectedElement.category ?? 'Unknown Category'}
                    </Badge>
                  </Stack>
                </Stack>

                <Divider margin="var(--ggui-spacing-2, 8px)" />

                <Stack direction="horizontal" gap="var(--ggui-spacing-12, 48px)" wrap>
                  <Stack gap="var(--ggui-spacing-1, 4px)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Atomic Number
                    </Text>
                    <Text weight="semibold" size="lg" color="var(--ggui-color-onSurface, #18181b)">
                      {selectedElement.atomicNumber}
                    </Text>
                  </Stack>

                  <Stack gap="var(--ggui-spacing-1, 4px)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Atomic Weight
                    </Text>
                    <Text weight="semibold" size="lg" color="var(--ggui-color-onSurface, #18181b)">
                      {selectedElement.atomicWeight ?? '-'} u
                    </Text>
                  </Stack>

                  <Stack gap="var(--ggui-spacing-1, 4px)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Position
                    </Text>
                    <Text weight="semibold" size="lg" color="var(--ggui-color-onSurface, #18181b)">
                      Row {selectedElement.row}, Column {selectedElement.col}
                    </Text>
                  </Stack>
                </Stack>
              </Stack>
            </Card>
          </Box>
        )}

        {!selectedElement && (
          <Box padding="var(--ggui-spacing-8, 32px)" style={{ textAlign: 'center' }}>
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Select an element to view detailed properties.
            </Text>
          </Box>
        )}

        <Spacer size={24} />
      </Stack>
    </Container>
  );
}
